mapper.select:
SELECT * FROM shop
WHERE city = #{city}

    AND district = #{district}


    AND status = #{status}

  AND is_delete = 0
ORDER BY rating_score DESC, create_time DESC
LIMIT #{limit}

SELECT * FROM shop WHERE is_recommended = 1 AND status = 1 AND review_status = 1
AND city = #{city}
AND is_delete = 0 ORDER BY rating_score DESC, coupon_verified_count DESC LIMIT #{limit}

mapper.update:
UPDATE shop
SET view_count = view_count + 1
WHERE shop_id = #{shopId}

UPDATE shop
SET click_count = click_count + 1
WHERE shop_id = #{shopId}

mapper.select:
SELECT CAST(s.shop_id AS CHAR) AS shopId, CAST(s.merchant_id AS CHAR) AS merchantId, s.shop_name AS shopName, s.shop_type AS shopType, s.province, s.city, s.district, s.address, s.latitude, s.longitude, s.phone, s.business_hours AS businessHours, s.shop_images AS shopImages, s.logo, s.description, s.status, s.is_recommended AS isRecommended, CAST(s.view_count AS CHAR) AS viewCount, CAST(s.click_count AS CHAR) AS clickCount, CAST(s.coupon_received_count AS CHAR) AS couponReceivedCount, CAST(s.coupon_verified_count AS CHAR) AS couponVerifiedCount, s.rating_score AS ratingScore, s.rating_count AS ratingCount, ROUND((6371 * ACOS( COS(RADIANS(#{latitude})) * COS(RADIANS(s.latitude)) * COS(RADIANS(s.longitude) - RADIANS(#{longitude})) + SIN(RADIANS(#{latitude})) * SIN(RADIANS(s.latitude)) )), 2) AS distance FROM shop s WHERE s.is_delete = 0 AND s.review_status = 1 AND s.status = 1 AND EXISTS ( SELECT 1 FROM coupon c WHERE ( c.shop_id = s.shop_id OR (c.shop_id IS NULL AND c.merchant_id = s.merchant_id) ) AND c.is_delete = 0 AND c.status = 1 AND c.valid_end_time > NOW() AND (c.remain_quantity > 0 OR c.total_quantity = -1) )
AND s.shop_name LIKE CONCAT('%', #{shopName}, '%')
AND s.is_recommended = #{isRecommended}
HAVING distance <= #{radius} ORDER BY distance ASC LIMIT #{offset}, #{pageSize}

SELECT CAST(m.merchant_id AS CHAR) AS merchantId, m.merchant_name AS merchantName, m.logo, m.rating_score AS ratingScore, m.rating_count AS ratingCount, MIN(distance_info.distance) AS distance, COUNT(DISTINCT distance_info.shop_id) AS shopCount, SUBSTRING_INDEX(GROUP_CONCAT(distance_info.latitude ORDER BY distance_info.distance), ',', 1) AS latitude, SUBSTRING_INDEX(GROUP_CONCAT(distance_info.longitude ORDER BY distance_info.distance), ',', 1) AS longitude FROM merchant m INNER JOIN ( SELECT s.shop_id, s.merchant_id, s.latitude, s.longitude, (6371 * ACOS( COS(RADIANS(#{latitude})) * COS(RADIANS(s.latitude)) * COS(RADIANS(s.longitude) - RADIANS(#{longitude})) + SIN(RADIANS(#{latitude})) * SIN(RADIANS(s.latitude)) )) AS distance FROM shop s WHERE s.is_delete = 0 AND s.review_status = 1 AND s.status = 1 ) distance_info ON m.merchant_id = distance_info.merchant_id WHERE m.is_delete = 0 AND m.review_status = 1 AND EXISTS ( SELECT 1 FROM coupon c WHERE c.merchant_id = m.merchant_id AND c.shop_id IS NULL AND c.is_delete = 0 AND c.status = 1 AND c.valid_end_time > NOW() AND (c.remain_quantity > 0 OR c.total_quantity = -1) )
AND m.merchant_name LIKE CONCAT('%', #{merchantName}, '%')
GROUP BY m.merchant_id, m.merchant_name, m.logo, m.rating_score, m.rating_count HAVING MIN(distance_info.distance) <= #{radius} ORDER BY MIN(distance_info.distance) ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(DISTINCT m.merchant_id) FROM merchant m INNER JOIN ( SELECT s.shop_id, s.merchant_id, (6371 * ACOS( COS(RADIANS(#{latitude})) * COS(RADIANS(s.latitude)) * COS(RADIANS(s.longitude) - RADIANS(#{longitude})) + SIN(RADIANS(#{latitude})) * SIN(RADIANS(s.latitude)) )) AS distance FROM shop s WHERE s.is_delete = 0 AND s.review_status = 1 AND s.status = 1 ) distance_info ON m.merchant_id = distance_info.merchant_id WHERE m.is_delete = 0 AND m.review_status = 1 AND EXISTS ( SELECT 1 FROM coupon c WHERE c.merchant_id = m.merchant_id AND c.shop_id IS NULL AND c.is_delete = 0 AND c.status = 1 AND c.valid_end_time > NOW() AND (c.remain_quantity > 0 OR c.total_quantity = -1) )
AND m.merchant_name LIKE CONCAT('%', #{merchantName}, '%')
HAVING MIN(distance_info.distance) <= #{radius}

SELECT CAST(m.merchant_id AS CHAR) AS merchantId, m.merchant_name AS merchantName, m.logo, m.rating_score AS ratingScore, m.rating_count AS ratingCount, MIN(distance_info.distance) AS distance, COUNT(DISTINCT distance_info.shop_id) AS shopCount, SUBSTRING_INDEX(GROUP_CONCAT(distance_info.latitude ORDER BY distance_info.distance), ',', 1) AS latitude, SUBSTRING_INDEX(GROUP_CONCAT(distance_info.longitude ORDER BY distance_info.distance), ',', 1) AS longitude FROM merchant m INNER JOIN ( SELECT s.shop_id, s.merchant_id, s.latitude, s.longitude, (6371 * ACOS( COS(RADIANS(#{latitude})) * COS(RADIANS(s.latitude)) * COS(RADIANS(s.longitude) - RADIANS(#{longitude})) + SIN(RADIANS(#{latitude})) * SIN(RADIANS(s.latitude)) )) AS distance FROM shop s WHERE s.is_delete = 0 AND s.review_status = 1 AND s.status = 1 ) distance_info ON m.merchant_id = distance_info.merchant_id INNER JOIN activity_shop aso ON aso.shop_id = distance_info.shop_id INNER JOIN activity a ON a.activity_id = aso.activity_id WHERE m.is_delete = 0 AND m.review_status = 1 AND a.is_delete = 0 AND a.status IN (1, 2, 3, 4)
AND m.merchant_name LIKE CONCAT('%', #{merchantName}, '%')
GROUP BY m.merchant_id, m.merchant_name, m.logo, m.rating_score, m.rating_count HAVING MIN(distance_info.distance) <= #{radius} ORDER BY MIN(distance_info.distance) ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(DISTINCT m.merchant_id) FROM merchant m INNER JOIN ( SELECT s.shop_id, s.merchant_id, (6371 * ACOS( COS(RADIANS(#{latitude})) * COS(RADIANS(s.latitude)) * COS(RADIANS(s.longitude) - RADIANS(#{longitude})) + SIN(RADIANS(#{latitude})) * SIN(RADIANS(s.latitude)) )) AS distance FROM shop s WHERE s.is_delete = 0 AND s.review_status = 1 AND s.status = 1 ) distance_info ON m.merchant_id = distance_info.merchant_id INNER JOIN activity_shop aso ON aso.shop_id = distance_info.shop_id INNER JOIN activity a ON a.activity_id = aso.activity_id WHERE m.is_delete = 0 AND m.review_status = 1 AND a.is_delete = 0 AND a.status IN (1, 2, 3, 4)
AND m.merchant_name LIKE CONCAT('%', #{merchantName}, '%')
HAVING MIN(distance_info.distance) <= #{radius}
